// ---------------------------------------------------------------
// Mail-Builder fuer alle 9 Event-Typen der Betreuer-App.
// Liest event_type aus dem Webhook-Body und produziert
// { to, subject, html, eventType, contractNumber, documentId }.
//
// Empfaenger-Mapping:
//   pending_approval     -> coordinator_email
//   betreuer_approved    -> betreuer_email
//   contract_created     -> betreuer_email
//   duplicate_detected   -> ADMIN_EMAIL
//   email_mismatch       -> ADMIN_EMAIL
//   document_expiring    -> betreuer_email
//   document_expired     -> ADMIN_EMAIL
//   freibetrag_warning   -> ADMIN_EMAIL
//   timesheet_approved   -> BUCHHALTUNG_EMAIL
// ---------------------------------------------------------------

const ADMIN_EMAIL        = 'admin@fes-credo.de';
const BUCHHALTUNG_EMAIL  = 'buchhaltung@fes-minden.de';
const FROM_EMAIL         = 'noreply@fes-credo.de';

const raw = $input.first().json;
const d   = raw.body || raw;   // n8n verschachtelt Webhook-Daten unter .body
const evt = d.event_type;

function esc(s){ return String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;','\'':'&#39;'}[c])); }
function money(n){ const x = Number(n||0).toFixed(2).split('.'); x[0]=x[0].replace(/\B(?=(\d{3})+(?!\d))/g,'.'); return x.join(',') + ' EUR'; }
function shellHtml(headline, lead, bodyHtml){
  return '<!DOCTYPE html><html lang="de"><body style="margin:0;padding:0;background:#eeeded;font-family:Arial,sans-serif">'+
    '<table width="100%" cellpadding="0" cellspacing="0" style="background:#eeeded"><tr><td align="center" style="padding:32px 15px">'+
      '<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#fff">'+
        '<tr><td style="background:#FBC900;height:6px"></td></tr>'+
        '<tr><td style="background:#575756;padding:30px 36px">'+
          '<p style="margin:0 0 6px;font-size:10px;color:#aaa;letter-spacing:3px;text-transform:uppercase">Betreuer-App &middot; FES Minden</p>'+
          '<h1 style="margin:0 0 6px;font-size:24px;color:#fff;line-height:1.2">'+esc(headline)+'</h1>'+
          '<p style="margin:0;color:#bbbbb9;font-size:13px">'+esc(lead)+'</p>'+
        '</td></tr>'+
        '<tr><td style="padding:28px 36px;color:#333;font-size:14px;line-height:1.6">'+bodyHtml+'</td></tr>'+
        '<tr><td style="background:#575756;padding:18px 36px;color:#aaa;font-size:11px">'+
          'Christlicher Schulverein Minden e.V. &bull; Kingsleyallee 6 &bull; 32425 Minden &bull; fes-minden.de'+
        '</td></tr>'+
        '<tr><td style="background:#FBC900;height:5px"></td></tr>'+
      '</table>'+
    '</td></tr></table></body></html>';
}
function kv(label, value){
  return '<p style="margin:0 0 6px"><span style="display:inline-block;min-width:160px;color:#888;text-transform:uppercase;font-size:11px;letter-spacing:1px">'+esc(label)+'</span> <strong>'+esc(value || '—')+'</strong></p>';
}

let to = '';
let subject = '';
let body = '';
let headline = '';
let lead = '';

switch (evt) {
  case 'pending_approval':
    to = d.coordinator_email || ADMIN_EMAIL;
    headline = 'Neue Betreuer-Registrierung';
    lead = 'Wartet auf Genehmigung im Koordinator-Dashboard.';
    subject = '[Betreuer] Neue Registrierung wartet: ' + (d.betreuer_name || '');
    body = kv('Betreuer', d.betreuer_name) + kv('E-Mail', d.betreuer_email) +
           kv('Schule', d.school_name + ' (' + d.school_code + ')') +
           kv('Vertragsnummer', d.contract_number) +
           '<p style="margin-top:18px">Bitte im Koordinator-Dashboard pruefen und freigeben.</p>';
    break;
  case 'betreuer_approved':
    to = d.betreuer_email;
    headline = 'Registrierung freigegeben';
    lead = 'Ihre Anmeldung wurde von der Schule bestaetigt.';
    subject = '[Betreuer] Ihre Registrierung ist freigegeben';
    body = '<p>Hallo ' + esc(d.betreuer_name) + ',</p>' +
           '<p>Ihre Registrierung fuer die Schule <strong>' + esc(d.school_name) + '</strong> wurde freigegeben. Sie koennen sich jetzt im Portal anmelden und mit dem Onboarding fortfahren.</p>' +
           kv('Vertragsnummer', d.contract_number);
    break;
  case 'contract_created':
    to = d.betreuer_email;
    headline = 'Vertragsentwurf erstellt';
    lead = 'Bitte im Portal pruefen.';
    subject = '[Betreuer] Vertragsentwurf ' + (d.contract_number || '');
    body = '<p>Hallo ' + esc(d.betreuer_name) + ',</p>' +
           '<p>fuer Ihre Taetigkeit wurde ein Vertragsentwurf angelegt:</p>' +
           kv('Vertragsnummer', d.contract_number) + kv('Schule', d.school_name) + kv('Taetigkeit', d.activity_type);
    break;
  case 'duplicate_detected':
    to = ADMIN_EMAIL;
    headline = 'Duplikat bei Registrierung';
    lead = 'Manuelle Pruefung erforderlich.';
    subject = '[Betreuer] Duplikat erkannt: ' + (d.new_betreuer_name || '');
    body = kv('Neue Registrierung', d.new_betreuer_name + ' (' + d.new_betreuer_email + ')') +
           kv('Bestehender Eintrag', d.existing_betreuer_name + ' (' + d.existing_betreuer_email + ')') +
           '<p style="margin-top:18px;color:#E2001A">Bitte im Admin pruefen, ob es sich um dieselbe Person handelt.</p>';
    break;
  case 'email_mismatch':
    to = ADMIN_EMAIL;
    headline = 'E-Mail-Abweichung bei Registrierung';
    lead = 'Bekannter Betreuer registriert sich mit anderer Adresse.';
    subject = '[Betreuer] E-Mail-Abweichung: ' + (d.betreuer_name || '');
    body = kv('Betreuer', d.betreuer_name) + kv('Neue E-Mail', d.new_email) + kv('Bisherige E-Mail', d.stored_email);
    break;
  case 'document_expiring':
    to = d.betreuer_email;
    headline = 'Dokument laeuft bald ab';
    lead = 'Bitte fristgerecht erneuern.';
    subject = '[Betreuer] ' + (d.document_type || 'Dokument') + ' laeuft in ' + (d.days_remaining || '?') + ' Tagen ab';
    body = '<p>Hallo ' + esc(d.betreuer_name) + ',</p>' +
           '<p>Ihr Dokument <strong>' + esc(d.document_type) + '</strong> laeuft am <strong>' + esc(d.expires_at) + '</strong> ab (' + esc(d.days_remaining) + ' Tage).</p>' +
           '<p>Bitte laden Sie rechtzeitig eine erneuerte Version ueber das Portal hoch.</p>';
    break;
  case 'document_expired':
    to = ADMIN_EMAIL;
    headline = 'Dokument abgelaufen';
    lead = 'Erneuerung ueberfaellig.';
    subject = '[Betreuer] Dokument abgelaufen: ' + (d.document_type || '') + ' / ' + (d.betreuer_name || '');
    body = kv('Betreuer', d.betreuer_name + ' (' + d.betreuer_email + ')') +
           kv('Dokument', d.document_type) + kv('Abgelaufen am', d.expired_at);
    break;
  case 'freibetrag_warning':
    to = ADMIN_EMAIL;
    const lvl = d.warning_level || '';
    const farb = lvl === 'red' ? '#E2001A' : (lvl === 'orange' ? '#F39200' : '#FBC900');
    headline = 'Freibetrag-Warnung (' + lvl + ')';
    lead = (d.percentage || '?') + ' % des Jahres-Freibetrags erreicht.';
    subject = '[Betreuer] Freibetrag ' + lvl + ': ' + (d.betreuer_name || '');
    body = kv('Betreuer', d.betreuer_name) + kv('Jahr', d.year) +
           kv('Auslastung', d.percentage + ' %') +
           kv('Bisher genutzt', money(d.total_used)) +
           kv('Verbleibend', money(d.remaining)) +
           kv('Limit', money(d.limit)) +
           '<p style="margin-top:14px;padding:10px 14px;border-left:4px solid '+farb+';background:#fafafa">Warnstufe: <strong>' + esc(lvl) + '</strong></p>';
    break;
  case 'timesheet_approved':
    to = BUCHHALTUNG_EMAIL;
    headline = 'Stundennachweis genehmigt';
    lead = 'Abrechnung kann angestossen werden.';
    subject = '[Betreuer] Abrechnung ' + (d.contract_number || '') + ' / ' + (d.month || '') + '.' + (d.year || '');
    body = kv('Betreuer', d.betreuer_name) +
           kv('Schule', d.school_name + ' (' + d.school_code + ')') +
           kv('Vertrag', d.contract_number) +
           kv('Zeitraum', d.month + '/' + d.year) +
           kv('Stunden', d.total_hours) +
           kv('Betrag', money(d.total_amount)) +
           kv('Projektnummer', d.projektnummer) +
           kv('Kreditorennummer', d.kreditorennummer) +
           (d.pdf_url ? '<p style="margin-top:14px">PDF im Portal: <code>' + esc(d.pdf_url) + '</code></p>' : '');
    break;
  default:
    return [{ json: { skip: true, reason: 'unknown_event_type', event_type: evt } }];
}

if (!to) {
  return [{ json: { skip: true, reason: 'missing_recipient', event_type: evt } }];
}

const html = shellHtml(headline, lead, body);

return [{
  json: {
    skip: false,
    eventType: evt,
    to: to,
    from: FROM_EMAIL,
    subject: subject,
    html: html,
    contractNumber: d.contract_number || null,
    documentId: d.document_id || null,
    sentAt: new Date().toISOString()
  }
}];

// Confirmation-Payload fuer den Django-Inbound-Webhook bauen.
// Schickt event_type=email_sent_confirmation mit event_id (uuid)
// + recipient + sent_at + ggf. contract_number / document_id zurueck.
const src = $input.first().json;
function uuid(){
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random()*16|0; const v = c==='x'?r:(r&0x3|0x8); return v.toString(16);
  });
}
return [{ json: {
  event_type: 'email_sent_confirmation',
  event_id: uuid(),
  recipient_email: src.to,
  sent_at: src.sentAt,
  contract_number: src.contractNumber,
  document_id: src.documentId
} }];
